script.text:

function load$GridBankAccount(g) {
  g.add_onResponseComplete(on$GridBankAccount$ResponseComplete);  
  g.add_commandEvent(on$GridBankAccount$ExecuteCommand);
}
function dispose$GridBankAccount(g) {
  try {g.remove_commandEvent(on$GridBankAccount$ExecuteCommand);} catch (ex) {}
  try {g.remove_onResponseComplete(on$GridBankAccount$ResponseComplete);} catch (ex) {}  
}
function on$GridBankAccount$ExecuteCommand(sender, e) {
  var action = e.type.Action, g = sender;
  switch (action) {
    case 'ImportData':
      show$Form(g, 'BankAccountImport');
      break;
    case 'Download':
      request$Download(g, action);
      break;
    default:
      break;
  }
}
function on$GridBankAccount$ResponseComplete(sender, e) {
  var g = e.object, context = e.type.Context, result = e.type.Result, o = e.type.Object;
  switch (context) {
    case 'Download':
      g._key = result[0].Value;
      break;
    default:
      break;
  }
}
function show$Form(g, c) {(g._authorize == 1) ? g.showForm(c) : $message.show($df.getResources(g._language, "Message.NotAccess"));}

      &DowloadScript;
